    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        //     {
        //         "clOrdId": "00001",
        //         "ordType": "MARKET",
        //         "ordStatus": "FILLED",
        //         "side": "BUY",
        //         "symbol": "USDC-USDT",
        //         "exOrdId": "281775861306290",
        //         "price": null,
        //         "text": "Fill",
        //         "lastShares": "30.0",
        //         "lastPx": "0.9999",
        //         "leavesQty": "0.0",
        //         "cumQty": "30.0",
        //         "avgPx": "0.9999",
        //         "timestamp": "1633940339619"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object clientOrderId = this.safeString(order, "clOrdId");
        Object type = this.safeStringLower(order, "ordType");
        Object statusId = this.safeString(order, "ordStatus");
        Object state = this.parseOrderState(statusId);
        Object side = this.safeStringLower(order, "side");
        Object marketId = this.safeString(order, "symbol");
        Object symbol = this.safeSymbol(marketId, market, "-");
        Object exchangeOrderId = this.safeString(order, "exOrdId");
        Object price = ((Helpers.isTrue((!Helpers.isEqual(type, "market"))))) ? this.safeString(order, "price") : null;
        Object average = this.safeNumber(order, "avgPx");
        Object timestamp = this.safeInteger(order, "timestamp");
        Object datetime = this.iso8601(timestamp);
        Object filled = this.safeString(order, "cumQty");
        Object remaining = this.safeString(order, "leavesQty");
        final Object finalType = type;
        Object result = this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "id", exchangeOrderId );
            put( "clientOrderId", clientOrderId );
            put( "datetime", datetime );
            put( "timestamp", timestamp );
            put( "lastTradeTimestamp", null );
            put( "status", state );
            put( "symbol", symbol );
            put( "type", finalType );
            put( "timeInForce", null );
            put( "side", side );
            put( "price", price );
            put( "average", average );
            put( "amount", null );
            put( "filled", filled );
            put( "remaining", remaining );
            put( "cost", null );
            put( "trades", new java.util.ArrayList<Object>(java.util.Arrays.asList()) );
            put( "fees", new java.util.ArrayList<Object>(java.util.Arrays.asList()) );
            put( "info", order );
        }});
        return result;
    }

    /**
     * @method
     * @name blockchaincom#createOrder
     * @description create a trade order
     * @see https://api.blockchain.com/v3/#createorder
     * @param {string} symbol unified symbol of the market to create an order in
     * @param {string} type 'market' or 'limit'
     * @param {string} side 'buy' or 'sell'
     * @param {float} amount how much of currency you want to trade in units of base currency
     * @param {float} [price] the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createOrder(Object symbol, Object type, Object side, Object amount, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object price = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object orderType = this.safeString(parameters, "ordType", type);
            Object uppercaseOrderType = ((String)orderType).toUpperCase();
            Object clientOrderId = this.safeString2(parameters, "clientOrderId", "clOrdId", this.uuid16());
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("ordType", "clientOrderId", "clOrdId")));
            final Object finalUppercaseOrderType = uppercaseOrderType;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "ordType", finalUppercaseOrderType );
                put( "symbol", Helpers.GetValue(market, "id") );
                put( "side", ((String)side).toUpperCase() );
                put( "orderQty", BlockchaincomCore.this.amountToPrecision(symbol, amount) );
                put( "clOrdId", clientOrderId );
            }};
            Object triggerPrice = this.safeValueN(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("triggerPrice", "stopPx", "stopPrice")));
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("triggerPrice", "stopPx", "stopPrice")));
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(uppercaseOrderType, "STOP")) || Helpers.isTrue(Helpers.isEqual(uppercaseOrderType, "STOPLIMIT"))))
            {
                if (Helpers.isTrue(Helpers.isEqual(triggerPrice, null)))
                {
                    throw new ArgumentsRequired((String)Helpers.add(Helpers.add(Helpers.add(this.id, " createOrder() requires a stopPx or triggerPrice param for a "), uppercaseOrderType), " order")) ;
                }
            }
            if (Helpers.isTrue(!Helpers.isEqual(triggerPrice, null)))
            {
                if (Helpers.isTrue(Helpers.isEqual(uppercaseOrderType, "MARKET")))
                {
                    Helpers.addElementToObject(request, "ordType", "STOP");
                } else if (Helpers.isTrue(Helpers.isEqual(uppercaseOrderType, "LIMIT")))
                {
                    Helpers.addElementToObject(request, "ordType", "STOPLIMIT");
                }
            }
            Object priceRequired = false;
            Object stopPriceRequired = false;
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(Helpers.GetValue(request, "ordType"), "LIMIT")) || Helpers.isTrue(Helpers.isEqual(Helpers.GetValue(request, "ordType"), "STOPLIMIT"))))
            {
                priceRequired = true;
            }
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(Helpers.GetValue(request, "ordType"), "STOP")) || Helpers.isTrue(Helpers.isEqual(Helpers.GetValue(request, "ordType"), "STOPLIMIT"))))
            {
                stopPriceRequired = true;
            }
            if (Helpers.isTrue(priceRequired))
            {
                Helpers.addElementToObject(request, "price", this.priceToPrecision(symbol, price));
            }
            if (Helpers.isTrue(stopPriceRequired))
            {
                Helpers.addElementToObject(request, "stopPx", this.priceToPrecision(symbol, triggerPrice));
            }
            Object response = (this.privatePostOrders(this.extend(request, parameters))).join();
            return this.parseOrder(response, market);
        });

    }

