    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        // deposit
        //
        //     {
        //         "depositId":"748e9180-be0d-4a80-e175-0156150efc95",
        //         "amount":0.009,
        //         "currency":"ETH",
        //         "address":"0xEC6B5929D454C8D9546d4221ace969E1810Fa92c",
        //         "state":"COMPLETED",
        //         "txHash":"582114562140e51a80b481c2dfebaf62b4ab9769b8ff54820bb67e34d4a3ab0c",
        //         "timestamp":1633697196241
        //     }
        //
        // withdrawal
        //
        //     {
        //         "amount":30.0,
        //         "currency":"USDT",
        //         "beneficiary":"cab00d11-6e7f-46b7-b453-2e8ef6f101fa", // blockchain specific id
        //         "withdrawalId":"99df5ef7-eab6-4033-be49-312930fbd1ea",
        //         "fee":34.005078,
        //         "state":"COMPLETED",
        //         "timestamp":1634218452549
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object type = null;
        Object id = null;
        Object amount = this.safeNumber(transaction, "amount");
        Object timestamp = this.safeInteger(transaction, "timestamp");
        Object currencyId = this.safeString(transaction, "currency");
        Object code = this.safeCurrencyCode(currencyId, currency);
        Object state = this.safeString(transaction, "state");
        if (Helpers.isTrue(Helpers.inOp(transaction, "depositId")))
        {
            type = "deposit";
            id = this.safeString(transaction, "depositId");
        } else if (Helpers.isTrue(Helpers.inOp(transaction, "withdrawalId")))
        {
            type = "withdrawal";
            id = this.safeString(transaction, "withdrawalId");
        }
        Object feeCost = ((Helpers.isTrue((Helpers.isEqual(type, "withdrawal"))))) ? this.safeNumber(transaction, "fee") : null;
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            final Object finalFeeCost = feeCost;
            fee = new java.util.HashMap<String, Object>() {{
                put( "currency", code );
                put( "cost", finalFeeCost );
            }};
        }
        Object address = this.safeString(transaction, "address");
        Object txid = this.safeString(transaction, "txhash");
        final Object finalId = id;
        final Object finalType = type;
        final Object finalFee = fee;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transaction );
            put( "id", finalId );
            put( "txid", txid );
            put( "timestamp", timestamp );
            put( "datetime", BlockchaincomCore.this.iso8601(timestamp) );
            put( "network", null );
            put( "addressFrom", null );
            put( "address", address );
            put( "addressTo", address );
            put( "tagFrom", null );
            put( "tag", null );
            put( "tagTo", null );
            put( "type", finalType );
            put( "amount", amount );
            put( "currency", code );
            put( "status", BlockchaincomCore.this.parseTransactionState(state) );
            put( "updated", null );
            put( "comment", null );
            put( "internal", null );
            put( "fee", finalFee );
        }};
    }

